patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 394dfca262e1..6399e712ce41 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3881,6 +3881,7 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     }
   }

+
   // select(C, Z, binop(select(C, X, Y), W)) -> select(C, Z, binop(Y, W))
   BinaryOperator *FalseBO;
   if (match(FalseVal, m_OneUse(m_BinOp(FalseBO))) && !FalseBO->isIntDivRem()) {
@@ -3990,6 +3991,20 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   if (Instruction *I = foldNestedSelects(SI, Builder))
     return I;

+  // select C2, (select C1, A, B), (select C1, B, A) -> select (xor C1, C2), B, A
+  if (SelectInst *TrueSI = dyn_cast<SelectInst>(TrueVal)) {
+    if (SelectInst *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
+      if (TrueSI->hasOneUse() && FalseSI->hasOneUse() &&
+          TrueSI->getCondition() == FalseSI->getCondition() &&
+          TrueSI->getTrueValue() == FalseSI->getFalseValue() &&
+          TrueSI->getFalseValue() == FalseSI->getTrueValue()) {
+        Value *Xor = Builder.CreateXor(TrueSI->getCondition(), CondVal);
+        return SelectInst::Create(Xor, TrueSI->getFalseValue(),
+                                  TrueSI->getTrueValue());
+      }
+    }
+  }
+
   // Match logical variants of the pattern,
   // and transform them iff that gets rid of inversions.
   //   (~x) | y  -->  ~(x & (~y))
@@ -4081,3 +4096,4 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {

   return nullptr;
 }
+

